	switch e {
		case 0:
			return "Station in use"
		case 1:
			return "Low SNR"
		case 2:
			return "Cycle Error"
		case 3:
			return "Blink"
	default:
		return fmt.Sprintf("%s(%d)", "StationStatusConst", int(e))
	}
